&DataLimite = YMDtoD(2026,12,31)
//Retorna Taxas IBS e CBS For Each Order (IbsCbsDta) Where IbsCbsDta <= &sdtCadastroTabelaImpostoCbs.CImpDtaIni &sdtCadastroTabelaImpostoCbs.IbsUnTax = IbsUnTax &sdtCadastroTabelaImpostoCbs.IbsUfTax = IbsUfTax &sdtCadastroTabelaImpostoCbs.IbsMunTax = IbsMunTax Exit EndFor
//receber tudo isso por paramentro //&sdtCadastroTabelaImpostoCbs.EmpCod //&sdtCadastroTabelaImpostoCbs.CImpTbFilCod //&sdtCadastroTabelaImpostoCbs.CImpLctCod //&sdtCadastroTabelaImpostoCbs.CImpOriUfeCod //&sdtCadastroTabelaImpostoCbs.CImpDstUfeCod //&sdtCadastroTabelaImpostoCbs.CImpGruImpCod //&sdtCadastroTabelaImpostoCbs.CImpCatCod //&sdtCadastroTabelaImpostoCbs.CImpDtaIni
//falta passar esse em todos os lugares para nota fiscal produto ou serviço; para Cte nao vai ter produto //&sdtCadastroTabelaImpostoCbs.ProCod
RetornaConfSistema.Call(&sdtCadastroTabelaImpostoCbs.EmpCod, &sdtCadastroTabelaImpostoCbs.CImpTbFilCod, domConfSistema.TCon160_FreteBaseCalculoIPI, &sdtCadastroTabelaImpostoCbs.TCon160_FreteBaseCalculoIPI) RetornaConfSistema.Call(&sdtCadastroTabelaImpostoCbs.EmpCod, &sdtCadastroTabelaImpostoCbs.CImpTbFilCod, domConfSistema.TCon144_FreteBaseCalculoICMS, &sdtCadastroTabelaImpostoCbs.TCon144_FreteBaseCalculoICMS) //FRETE
For Each Order EmpCod,CImpTbFilCod,CImpLctCod,CImpOriUfeCod,CImpDstUfeCod,CImpGruImpCod,CImpCatCod,(CImpDtaIni) Where EmpCod = &sdtCadastroTabelaImpostoCbs.EmpCod Where CImpTbFilCod = &sdtCadastroTabelaImpostoCbs.CImpTbFilCod Where CImpLctCod = &sdtCadastroTabelaImpostoCbs.CImpLctCod Where CImpOriUfeCod = &sdtCadastroTabelaImpostoCbs.CImpOriUfeCod Where CImpDstUfeCod = &sdtCadastroTabelaImpostoCbs.CImpDstUfeCod Where CImpGruImpCod = &sdtCadastroTabelaImpostoCbs.CImpGruImpCod Where CImpCatCod = &sdtCadastroTabelaImpostoCbs.CImpCatCod Where CImpDtaIni <= &sdtCadastroTabelaImpostoCbs.CImpDtaIni
&sdtCadastroTabelaImpostoCbs.sts = 'S' //Tabela Localizada
&sdtCadastroTabelaImpostoCbs.CImpCfoCod = CImpCfoCod
&sdtCadastroTabelaImpostoCbs.CImpCstCod = CImpCstCod &sdtCadastroTabelaImpostoCbs.CImpObsInf = CImpObsInf
&sdtCadastroTabelaImpostoCbs.CImpAlqMVA = CImpAlqMVA &sdtCadastroTabelaImpostoCbs.CImpAlqIcmInt = CImpAlqIcmInt &sdtCadastroTabelaImpostoCbs.CImpRedAlqIcmInt = CImpRedAlqIcmInt &sdtCadastroTabelaImpostoCbs.CImpAlqIcmExt = CImpAlqIcmExt &sdtCadastroTabelaImpostoCbs.CImpRedAlqIcmExt = CImpRedAlqIcmExt &sdtCadastroTabelaImpostoCbs.CImpDif = CImpDif &sdtCadastroTabelaImpostoCbs.CImpCBenef = CImpCBenef &sdtCadastroTabelaImpostoCbs.CImpAlqIcmUFDest = CImpAlqIcmUFDest &sdtCadastroTabelaImpostoCbs.CImpIcmsMotDes = CImpIcmsMotDes &sdtCadastroTabelaImpostoCbs.CImpTaxFecop = CImpTaxFecop &sdtCadastroTabelaImpostoCbs.CImpIcmsRet = CImpIcmsRet &sdtCadastroTabelaImpostoCbs.CImpAlqIcmStUF = CImpAlqIcmStUF
//INCLUIR E EXCLUIR &sdtCadastroTabelaImpostoCbs.CImpIncIPI = CImpIncIPI &sdtCadastroTabelaImpostoCbs.CImpExcPisCofins = CImpExcPisCofins
//IPI &sdtCadastroTabelaImpostoCbs.CImpCstIpi = CImpCstIpi &sdtCadastroTabelaImpostoCbs.CImpIpi = CImpIpi &sdtCadastroTabelaImpostoCbs.CImpIpiEnq = CImpIpiEnq
//INSS &sdtCadastroTabelaImpostoCbs.CImpAlqInss = CImpAlqInss
//PIS e COFINS &Varchar = CImpCstPisCofins.ToString() //JDF gambiarra para compatibilidade com cstcofins na nota. ate remover eles &sdtCadastroTabelaImpostoCbs.NfeCstCofins.FromString(&Varchar) //JDF gambiarra para compatibilidade com cstcofins na nota. ate remover eles
&sdtCadastroTabelaImpostoCbs.CImpCstPisCofins = CImpCstPisCofins &sdtCadastroTabelaImpostoCbs.CImpCofins = CImpCofins &sdtCadastroTabelaImpostoCbs.CImpCofinsRed = CImpCofinsRed &sdtCadastroTabelaImpostoCbs.CImpPis = CImpPis &sdtCadastroTabelaImpostoCbs.CImpPisRed = CImpPisRed
//CST e cClassTrib Tipo lancamento &CImpClsCST = CImpClsCST &CImpClsTrib = CImpClsTrib
if &sdtCadastroTabelaImpostoCbs.Tipo = 'CTE' //para CTE fazer a verificacao abaixo. Do Case Case CImpCstCod = domSituacaoTributariaVarchar.CST00 &sdtCadastroTabelaImpostoCbs.CteImpCst = ClassificacaoCst.Normal &sdtCadastroTabelaImpostoCbs.CteConSplNac = Status_SimNao.Nao Case CImpCstCod = domSituacaoTributariaVarchar.CST20 &sdtCadastroTabelaImpostoCbs.CteImpCst = ClassificacaoCst.reduzida &sdtCadastroTabelaImpostoCbs.CteConSplNac = Status_SimNao.Nao Case CImpCstCod = domSituacaoTributariaVarchar.CST40 &sdtCadastroTabelaImpostoCbs.CteImpCst = ClassificacaoCst.Isento &sdtCadastroTabelaImpostoCbs.CteConSplNac = Status_SimNao.Nao Case CImpCstCod = domSituacaoTributariaVarchar.CST41 &sdtCadastroTabelaImpostoCbs.CteImpCst = ClassificacaoCst.NaoTributada &sdtCadastroTabelaImpostoCbs.CteConSplNac = Status_SimNao.Nao Case CImpCstCod = domSituacaoTributariaVarchar.CST51 &sdtCadastroTabelaImpostoCbs.CteImpCst = ClassificacaoCst.Deferido &sdtCadastroTabelaImpostoCbs.CteConSplNac = Status_SimNao.Nao Case CImpCstCod = domSituacaoTributariaVarchar.CST60 &sdtCadastroTabelaImpostoCbs.CteImpCst = ClassificacaoCst.Substituicao &sdtCadastroTabelaImpostoCbs.CteConSplNac = Status_SimNao.Nao Case CImpCstCod = domSituacaoTributariaVarchar.CST90 &sdtCadastroTabelaImpostoCbs.CteImpCst = ClassificacaoCst.outros &sdtCadastroTabelaImpostoCbs.CteConSplNac = Status_SimNao.Nao
OtherWise &sdtCadastroTabelaImpostoCbs.CteImpCst = ClassificacaoCst.Simples &sdtCadastroTabelaImpostoCbs.CteConSplNac = Status_SimNao.Sim EndCase Endif
//Observacoes da tabela if &sdtCadastroTabelaImpostoCbs.IsRetornarObs = true &sdtCadastroTabelaImpostoCbs.Observacao.Clear() for Each Order EmpCod,CImpTbFilCod,CImpLctCod,CImpOriUfeCod,CImpDstUfeCod,CImpGruImpCod,CImpCatCod,CImpDtaIni, ObsCod &sdtCadastroTabelaImpostoCbsObservacao = new() &sdtCadastroTabelaImpostoCbsObservacao.ObsCod = ObsCod &sdtCadastroTabelaImpostoCbsObservacao.ObsNom = ObsNom &sdtCadastroTabelaImpostoCbs.Observacao.Add(&sdtCadastroTabelaImpostoCbsObservacao) EndFor Endif
Exit When none &sdtCadastroTabelaImpostoCbs.sts = 'N' //Nao Configurada EndFor
//seta o padrao no CST Regular &sdtCadastroTabelaImpostoCbs.NfeRegIbsSit = '000' &sdtCadastroTabelaImpostoCbs.NfeRegIbsClassTrib = '000001'
//Tipo Lancamento (FIxo ou padrao) For EAch ORder EmpCod, LctCod Where EmpCod = &sdtCadastroTabelaImpostoCbs.EmpCod Where LctCod = &sdtCadastroTabelaImpostoCbs.CImpLctCod
//Tipo de lancamento codigo padrao &sdtCadastroTabelaImpostoCbs.CImpClsCST = LctClsCST &sdtCadastroTabelaImpostoCbs.CImpClsTrib = LctClsTrib &LctClsTribFix = LctClsTribFix
Exit EndFor
//produto (Substitui Padrao do Tipo de Lancamento) if &sdtCadastroTabelaImpostoCbs.ProCod > 0 and &sdtCadastroTabelaImpostoCbs.Tipo <> 'CTE' For Each Order EmpCod, ProCod Where EmpCod = &sdtCadastroTabelaImpostoCbs.EmpCod Where ProCod = &sdtCadastroTabelaImpostoCbs.ProCod
retornaClassTribAnexo.Call(EmpCod, ProAnxCod, &ProCltSitCod, &ProCltClsTrib)
Do CAse Case not &ProCltSitCod.IsEmpty() and not &ProCltClsTrib.IsEmpty() if &LctClsTribFix = false
if not &sdtCadastroTabelaImpostoCbs.CImpClsCST.IsEmpty() and not &sdtCadastroTabelaImpostoCbs.CImpClsTrib.IsEmpty() &InfoSdtCadastroTabelaImpostoCbs = new() &InfoSdtCadastroTabelaImpostoCbs.CImpDtaIni = &sdtCadastroTabelaImpostoCbs.CImpDtaIni &InfoSdtCadastroTabelaImpostoCbs.CImpClsCST = &sdtCadastroTabelaImpostoCbs.CImpClsCST &InfoSdtCadastroTabelaImpostoCbs.CImpClsTrib = &sdtCadastroTabelaImpostoCbs.CImpClsTrib prcRetornaClassTrib_IBSCBS.Call(&InfoSdtCadastroTabelaImpostoCbs) //retorna config
if &InfoSdtCadastroTabelaImpostoCbs.CltClsIsTribReg = 'N' //caso o anterior nao solicite trib regular, então é um regular. &sdtCadastroTabelaImpostoCbs.NfeRegIbsSit = &sdtCadastroTabelaImpostoCbs.CImpClsCST &sdtCadastroTabelaImpostoCbs.NfeRegIbsClassTrib = &sdtCadastroTabelaImpostoCbs.CImpClsTrib Endif Endif
&sdtCadastroTabelaImpostoCbs.CImpClsCST = &ProCltSitCod &sdtCadastroTabelaImpostoCbs.CImpClsTrib = &ProCltClsTrib Else
&InfoSdtCadastroTabelaImpostoCbs = new() &InfoSdtCadastroTabelaImpostoCbs.CImpDtaIni = &sdtCadastroTabelaImpostoCbs.CImpDtaIni &InfoSdtCadastroTabelaImpostoCbs.CImpClsCST = &ProCltSitCod &InfoSdtCadastroTabelaImpostoCbs.CImpClsTrib = &ProCltClsTrib prcRetornaClassTrib_IBSCBS.Call(&InfoSdtCadastroTabelaImpostoCbs) //retorna config
if &InfoSdtCadastroTabelaImpostoCbs.CltClsIsTribReg = 'N' //caso o anterior nao solicite trib regular, então é um regular. &sdtCadastroTabelaImpostoCbs.NfeRegIbsSit = &ProCltSitCod &sdtCadastroTabelaImpostoCbs.NfeRegIbsClassTrib = &ProCltClsTrib Endif Endif
Case not ProCatCltClsTrib.IsEmpty() and not ProCatCltClsTrib.IsNull() and not ProCatCltSitCod.IsEmpty() and not ProCatCltSitCod.IsNull() if &LctClsTribFix = false if not &sdtCadastroTabelaImpostoCbs.CImpClsCST.IsEmpty() and not &sdtCadastroTabelaImpostoCbs.CImpClsTrib.IsEmpty() &InfoSdtCadastroTabelaImpostoCbs = new() &InfoSdtCadastroTabelaImpostoCbs.CImpDtaIni = &sdtCadastroTabelaImpostoCbs.CImpDtaIni &InfoSdtCadastroTabelaImpostoCbs.CImpClsCST = &sdtCadastroTabelaImpostoCbs.CImpClsCST &InfoSdtCadastroTabelaImpostoCbs.CImpClsTrib = &sdtCadastroTabelaImpostoCbs.CImpClsTrib prcRetornaClassTrib_IBSCBS.Call(&InfoSdtCadastroTabelaImpostoCbs) //retorna config
if &InfoSdtCadastroTabelaImpostoCbs.CltClsIsTribReg = 'N' //caso o anterior nao solicite trib regular, então é um regular. &sdtCadastroTabelaImpostoCbs.NfeRegIbsSit = &sdtCadastroTabelaImpostoCbs.CImpClsCST &sdtCadastroTabelaImpostoCbs.NfeRegIbsClassTrib = &sdtCadastroTabelaImpostoCbs.CImpClsTrib Endif Endif
&sdtCadastroTabelaImpostoCbs.CImpClsCST = ProCatCltSitCod &sdtCadastroTabelaImpostoCbs.CImpClsTrib = ProCatCltClsTrib Else &InfoSdtCadastroTabelaImpostoCbs = new() &InfoSdtCadastroTabelaImpostoCbs.CImpDtaIni = &sdtCadastroTabelaImpostoCbs.CImpDtaIni &InfoSdtCadastroTabelaImpostoCbs.CImpClsCST = ProCatCltSitCod &InfoSdtCadastroTabelaImpostoCbs.CImpClsTrib = ProCatCltClsTrib prcRetornaClassTrib_IBSCBS.Call(&InfoSdtCadastroTabelaImpostoCbs) //retorna config
if &InfoSdtCadastroTabelaImpostoCbs.CltClsIsTribReg = 'N' //caso o anterior nao solicite trib regular, então é um regular. &sdtCadastroTabelaImpostoCbs.NfeRegIbsSit = ProCatCltSitCod &sdtCadastroTabelaImpostoCbs.NfeRegIbsClassTrib = ProCatCltClsTrib Endif Endif EndCase EndFor Endif
//caso o Cst e cClssTrib da Tabela de impostos estiver preenchido pega e substitui o configurado no Tipo de Lancamento. if not &CImpClsCST.IsEmpty() and not &CImpClsTrib.IsEmpty() //Padrao fixo do tipo lancamento ignora.
&InfoSdtCadastroTabelaImpostoCbs = new() &InfoSdtCadastroTabelaImpostoCbs.CImpDtaIni = &sdtCadastroTabelaImpostoCbs.CImpDtaIni &InfoSdtCadastroTabelaImpostoCbs.CImpClsCST = &sdtCadastroTabelaImpostoCbs.CImpClsCST &InfoSdtCadastroTabelaImpostoCbs.CImpClsTrib = &sdtCadastroTabelaImpostoCbs.CImpClsTrib prcRetornaClassTrib_IBSCBS.Call(&InfoSdtCadastroTabelaImpostoCbs) //retorna config
if &InfoSdtCadastroTabelaImpostoCbs.CltClsIsTribReg = 'N' //caso o anterior nao solicite trib regular, então é um regular.
&sdtCadastroTabelaImpostoCbs.NfeRegIbsSit = &sdtCadastroTabelaImpostoCbs.CImpClsCST &sdtCadastroTabelaImpostoCbs.NfeRegIbsClassTrib = &sdtCadastroTabelaImpostoCbs.CImpClsTrib Endif
&sdtCadastroTabelaImpostoCbs.CImpClsCST = &CImpClsCST &sdtCadastroTabelaImpostoCbs.CImpClsTrib = &CImpClsTrib Endif
//classificacao regular if &sdtCadastroTabelaImpostoCbs.NfeRegIbsSit.IsEmpty() &sdtCadastroTabelaImpostoCbs.NfeRegIbsSit = '000' &sdtCadastroTabelaImpostoCbs.NfeRegIbsClassTrib = '000001' Endif
if &sdtCadastroTabelaImpostoCbs.CImpClsCST.IsEmpty() and Serverdate() < &DataLimite// &sdtCadastroTabelaImpostoCbs.CImpClsCST = '000' &sdtCadastroTabelaImpostoCbs.CImpClsTrib = '000001' Endif
//IBS CBS //Agora temos os dois codigos, vamos consultar For Each Order CltSitCod, CltClsTrib Where CltSitCod = &sdtCadastroTabelaImpostoCbs.CImpClsCST Where CltClsTrib = &sdtCadastroTabelaImpostoCbs.CImpClsTrib
//Tipos de Documentos &sdtCadastroTabelaImpostoCbs.CltClsIsNfce = CltClsIsNfce &sdtCadastroTabelaImpostoCbs.CltClsIsNfe = CltClsIsNfe &sdtCadastroTabelaImpostoCbs.CltClsIsNfse = CltClsIsNfse &sdtCadastroTabelaImpostoCbs.CltClsIsCte = CltClsIsCte &sdtCadastroTabelaImpostoCbs.CltClsIsCteOs = CltClsIsCteOs
&sdtCadastroTabelaImpostoCbs.CltClsIsExtCred = CltClsIsExtCred //extorno de credito &sdtCadastroTabelaImpostoCbs.CltClsIsPre = CltClsIsPre //credito presumido //&sdtCadastroTabelaImpostoCbs.CltClsIsRedBas = CltClsIsRedBas //Reducao de Base &sdtCadastroTabelaImpostoCbs.CltClsIsTribReg = CltClsIsTribReg //Exige tributacao regular &sdtCadastroTabelaImpostoCbs.CltClsTipAliq = CltClsTipAliq //Tipo Aliquota &sdtCadastroTabelaImpostoCbs.CltClsDtaFim = CltClsDtaFim &sdtCadastroTabelaImpostoCbs.CltClsDtaIni = CltClsDtaIni
&sdtCadastroTabelaImpostoCbs.Cltind_gIBSCBS = Cltind_gIBSCBS //Gera campos gIBS &sdtCadastroTabelaImpostoCbs.CltIsDif = CltIsDif //é diferido.
//reducao das taxas &sdtCadastroTabelaImpostoCbs.CltClsRedIbs = CltClsRedIbs &sdtCadastroTabelaImpostoCbs.CltClsRedCbs = CltClsRedCbs
Exit EndFor
//Verificar a taxa na UF //CImpDstUfeCod //&sdtCadastroTabelaImpostoCbs.IbsUfTax = IbsUfTax
//verificar a taxa no Municipio //&DstCidCod //&sdtCadastroTabelaImpostoCbs.IbsMunTax = IbsMunTax
//calcula as taxas efetivas. if &sdtCadastroTabelaImpostoCbs.CltClsTipAliq = TipoAliquotaIbsCbs.SemAliquota &sdtCadastroTabelaImpostoCbs.IbsUfTaxEfe = 0 &sdtCadastroTabelaImpostoCbs.IbsUfTax = 0 &sdtCadastroTabelaImpostoCbs.IbsUfTax = 0 &sdtCadastroTabelaImpostoCbs.CltClsRedIbs = 0
&sdtCadastroTabelaImpostoCbs.IbsMunTaxEfe = 0 &sdtCadastroTabelaImpostoCbs.IbsMunTax = 0 &sdtCadastroTabelaImpostoCbs.IbsMunTax = 0 &sdtCadastroTabelaImpostoCbs.CltClsRedIbs = 0
&sdtCadastroTabelaImpostoCbs.IbsUnTaxEfe = 0 &sdtCadastroTabelaImpostoCbs.IbsUnTax = 0 &sdtCadastroTabelaImpostoCbs.IbsUnTax = 0 &sdtCadastroTabelaImpostoCbs.CltClsRedCbs = 0 Else &sdtCadastroTabelaImpostoCbs.IbsUfTaxEfe = round(&sdtCadastroTabelaImpostoCbs.IbsUfTax - (&sdtCadastroTabelaImpostoCbs.IbsUfTax * (&sdtCadastroTabelaImpostoCbs.CltClsRedIbs*0.01)),4) &sdtCadastroTabelaImpostoCbs.IbsMunTaxEfe = round(&sdtCadastroTabelaImpostoCbs.IbsMunTax - (&sdtCadastroTabelaImpostoCbs.IbsMunTax * (&sdtCadastroTabelaImpostoCbs.CltClsRedIbs*0.01)), 4) &sdtCadastroTabelaImpostoCbs.IbsUnTaxEfe = round(&sdtCadastroTabelaImpostoCbs.IbsUnTax - (&sdtCadastroTabelaImpostoCbs.IbsUnTax * (&sdtCadastroTabelaImpostoCbs.CltClsRedCbs*0.01)),4) Endif
//diferimento if &sdtCadastroTabelaImpostoCbs.CltIsDif = 'S' //Diferido &sdtCadastroTabelaImpostoCbs.NfeIbsUfPerDif = 100 &sdtCadastroTabelaImpostoCbs.NfeIbsMunPerDif = 100 &sdtCadastroTabelaImpostoCbs.NfeCbsPerDif = 100 Endif
//caso precise da tributacao regular, retorna ela. if &sdtCadastroTabelaImpostoCbs.CltClsIsTribReg = 'S' &RegularSdtCadastroTabelaImpostoCbs.CImpDtaIni = &sdtCadastroTabelaImpostoCbs.CImpDtaIni &RegularSdtCadastroTabelaImpostoCbs.CImpClsCST = &sdtCadastroTabelaImpostoCbs.NfeRegIbsSit &RegularSdtCadastroTabelaImpostoCbs.CImpClsTrib = &sdtCadastroTabelaImpostoCbs.NfeRegIbsClassTrib prcRetornaClassTrib_IBSCBS.Call(&RegularSdtCadastroTabelaImpostoCbs)
&sdtCadastroTabelaImpostoCbs.NfeRegIbsUfeTaxEfe = round(&RegularSdtCadastroTabelaImpostoCbs.IbsUfTax - (&RegularSdtCadastroTabelaImpostoCbs.IbsUfTax * (&RegularSdtCadastroTabelaImpostoCbs.CltClsRedIbs*0.01)),4) //&sdtCadastroTabelaImpostoCbs.NfeRegIbsUfeVlr &sdtCadastroTabelaImpostoCbs.NfeRegIbsMunTaxEfe = round(&RegularSdtCadastroTabelaImpostoCbs.IbsMunTax - (&RegularSdtCadastroTabelaImpostoCbs.IbsMunTax * (&RegularSdtCadastroTabelaImpostoCbs.CltClsRedIbs*0.01)), 4) //&sdtCadastroTabelaImpostoCbs.NfeRegIbsMunVlr &sdtCadastroTabelaImpostoCbs.NfeRegCbsTaxEfe = round(&RegularSdtCadastroTabelaImpostoCbs.IbsUnTax - (&RegularSdtCadastroTabelaImpostoCbs.IbsUnTax * (&RegularSdtCadastroTabelaImpostoCbs.CltClsRedCbs*0.01)),4) //&sdtCadastroTabelaImpostoCbs.NfeRegCbsTaxVlr Endif
